-- 1. MISSING INDEXES (Performance)
-- ═════════════════════════════════════════════════════════════════════════════

-- conversations: frequently queried by client_id for context
CREATE INDEX IF NOT EXISTS idx_conversations_client_id 
    ON conversations(client_id);
CREATE INDEX IF NOT EXISTS idx_conversations_created_at 
    ON conversations(created_at DESC);

-- bookings: queried by client_id, status, date
CREATE INDEX IF NOT EXISTS idx_bookings_client_id 
    ON bookings(client_id);
CREATE INDEX IF NOT EXISTS idx_bookings_status 
    ON bookings(status);
CREATE INDEX IF NOT EXISTS idx_bookings_date 
    ON bookings(date);
CREATE INDEX IF NOT EXISTS idx_bookings_market_id 
    ON bookings(market_id);

-- clients: queried by telegram_id, market_id
CREATE INDEX IF NOT EXISTS idx_clients_telegram_id 
    ON clients(telegram_id);
CREATE INDEX IF NOT EXISTS idx_clients_market_id 
    ON clients(market_id);
CREATE INDEX IF NOT EXISTS idx_clients_stage 
    ON clients(stage);

-- tours: queried by market_id, category, active
CREATE INDEX IF NOT EXISTS idx_tours_market_id 
    ON tours(market_id);
CREATE INDEX IF NOT EXISTS idx_tours_category 
    ON tours(category);
CREATE INDEX IF NOT EXISTS idx_tours_active_sort 
    ON tours(active, sort_order);

-- client_memory: queried by client_id
CREATE INDEX IF NOT EXISTS idx_client_memory_client_id 
    ON client_memory(client_id);

-- knowledge: queried by market_id for context
CREATE INDEX IF NOT EXISTS idx_knowledge_market_id 
    ON knowledge(market_id);
CREATE INDEX IF NOT EXISTS idx_knowledge_tags 
    ON knowledge USING gin(tags);

-- action_history: queried by client_id and timestamp
CREATE INDEX IF NOT EXISTS idx_action_history_client_id 
    ON action_history(client_id);
CREATE INDEX IF NOT EXISTS idx_action_history_created_at 
    ON action_history(created_at DESC);

-- payments: queried by booking_id
CREATE INDEX IF NOT EXISTS idx_payments_booking_id 
    ON payments(booking_id);

-- reviews: queried by tour_id, client_id
CREATE INDEX IF NOT EXISTS idx_reviews_tour_id 
    ON reviews(tour_id);
CREATE INDEX IF NOT EXISTS idx_reviews_client_id 
    ON reviews(client_id);

