-- 2. MISSING RLS POLICIES (Security)
-- ═════════════════════════════════════════════════════════════════════════════

-- Enable RLS on all tables (idempotent)
ALTER TABLE IF EXISTS bookings ENABLE ROW LEVEL SECURITY;
ALTER TABLE IF EXISTS payments ENABLE ROW LEVEL SECURITY;
ALTER TABLE IF EXISTS reviews ENABLE ROW LEVEL SECURITY;

-- bookings: anon can only read their own via RPC, service_role full access
DROP POLICY IF EXISTS "bookings_service_full" ON bookings;
CREATE POLICY "bookings_service_full" 
    ON bookings FOR ALL 
    TO service_role 
    USING (true) 
    WITH CHECK (true);

DROP POLICY IF EXISTS "bookings_anon_read" ON bookings;
CREATE POLICY "bookings_anon_read" 
    ON bookings FOR SELECT 
    TO anon 
    USING (true);  -- Controlled via RPC parameters

-- payments: restrict access to service_role only
DROP POLICY IF EXISTS "payments_service_full" ON payments;
CREATE POLICY "payments_service_full" 
    ON payments FOR ALL 
    TO service_role 
    USING (true) 
    WITH CHECK (true);

-- reviews: anon can insert, service_role full access
DROP POLICY IF EXISTS "reviews_anon_insert" ON reviews;
CREATE POLICY "reviews_anon_insert" 
    ON reviews FOR INSERT 
    TO anon 
    WITH CHECK (true);

DROP POLICY IF EXISTS "reviews_service_full" ON reviews;
CREATE POLICY "reviews_service_full" 
    ON reviews FOR ALL 
    TO service_role 
    USING (true) 
    WITH CHECK (true);

-- conversations: add rate limiting check (max 100 messages per client per hour)
-- Note: This is a soft limit enforced at the application level
CREATE OR REPLACE FUNCTION check_conversation_rate_limit(p_client_id UUID)
RETURNS BOOLEAN
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    msg_count INT;
BEGIN
    SELECT COUNT(*) INTO msg_count
    FROM conversations
    WHERE client_id = p_client_id
      AND created_at > NOW() - INTERVAL '1 hour';
    
    RETURN msg_count < 100;  -- Max 100 messages per hour per client
END;
$$;

-- Update conversations RLS to include rate limit check
DROP POLICY IF EXISTS "conversations_anon_insert_site" ON conversations;
CREATE POLICY "conversations_anon_insert_site" 
    ON conversations FOR INSERT 
    TO anon 
    WITH CHECK (
        check_conversation_rate_limit(client_id)
    );

