-- 3. COMPOSITE INDEXES (Query Performance)
-- ═════════════════════════════════════════════════════════════════════════════

-- Frequent query pattern: get active tours by market, ordered by sort
CREATE INDEX IF NOT EXISTS idx_tours_market_active_sort 
    ON tours(market_id, active, sort_order) 
    WHERE active = true;

-- Frequent query pattern: get bookings for reminders (status + date)
CREATE INDEX IF NOT EXISTS idx_bookings_status_date 
    ON bookings(status, date) 
    WHERE status IN ('pending', 'confirmed');

-- Frequent query pattern: clients by stage for funnel analysis
CREATE INDEX IF NOT EXISTS idx_clients_stage_market 
    ON clients(stage, market_id);

